def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 8):
            base = (ratio ** j) / j
            if j % 2 == 0:
                base *= 1.1
            else:
                base *= 0.9
            if base < 0.05:
                base *= 2
            score += base
        if capacity > item * 3:
            score *= 0.7
            for k in range(1, 4):
                score -= (ratio ** k) * 0.05 * k
        elif capacity < item * 1.2:
            score *= 1.7
            for k in range(5, 10):
                score += (ratio ** k) / (k * 2)
        else:
            for m in range(3):
                if m == 0 and ratio > 0.5:
                    score *= 1.3
                elif m == 1 and ratio < 0.3:
                    score *= 0.85
                elif m == 2 and capacity % 2 == 0:
                    score += 0.1
        if score < 0:
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
        for i in range(len(priorities)):
            if priorities[i] == np.inf:
                priorities[i] = max_priority * 15
    else:
        priorities.fill(np.inf)
    return priorities
